import type { ReactNode } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
interface File {
    src: string;
    fileName?: string;
}
export interface PDFFile extends File {
}
export interface ImageFile extends File {
    alt: string;
}
export interface WordFile extends File {
}
export interface PreviewProps extends TestComponentProps {
    /**
     * Дополнительный CSS класс для стилизации
     */
    className?: string;
    /**
     * Режим модального окна
     * @default false
     */
    modal?: boolean;
    /**
     * Тип контента - pdf/img/docx
     */
    type: 'pdf' | 'img' | 'docx';
    /**
     * Файл для отображения
     * @type PDFFile / ImageFile / WordFile
     */
    value: PDFFile | ImageFile | WordFile;
    /**
     * ID элемента в который монтируется React Portal
     * @default root
     */
    applicationRootId?: string;
    /**
     * Обработчик клика по крестику в хедере
     * Обработчик может игнорировать параметр события
     */
    onClose?: (event: any) => void;
    /**
     * Обработчик кнопки раскрытия в полный экран
     * Кнопка отрисовывается если прокинуть onExpand, только не в модальном режиме
     * Обработчик может игнорировать параметр события
     */
    onExpand?: (event: any) => void;
    /**
     * Включить кнопки зума
     * @default true
     */
    enableZoom?: boolean;
    /**
     * Включить кнопки поворота
     * @default true
     */
    enableRotation?: boolean;
    /**
     * Дополнительные кнопки в Header
     */
    headerCustomElements?: ReactNode[] | ReactNode;
    /**
     * Навигация по файлам.
     */
    navigation?: {
        /**
         * Обработчик клика по кнопке "вперёд"
         * Обработчик может игнорировать параметр события
         */
        onClickNext: (event: any) => void;
        /**
         * Обработчик клика по кнопке "назад"
         * Обработчик может игнорировать параметр события
         */
        onClickPrev: (event: any) => void;
        max: number;
        value: number;
    };
    /**
     * Галлерея:
     * - для изображений (`type="img"`) — объект с настройками миниатюр
     * - для PDF (`type="pdf"`) — `true` для включения списка страниц справа
     * - для Word (`type="docx"`) — `true` для включения списка страниц справа
     */
    gallery?: PDFGalleryProps | ImageGalleryProps | WordGalleryProps;
    /**
     * Описание. Доступно только при modal=false
     */
    description?: string;
}
export type PDFGalleryProps = boolean;
export type WordGalleryProps = boolean;
export interface ImageGalleryProps {
    selectedIndex: number;
    onClick?: (index: number) => void;
    content: ImageFile[];
}
export interface BasePreviewProps {
    scale: number;
    onInitialScale: (scale: number) => void;
    rotation: number;
}
export {};
